import React, { useState } from "react";

const tips = [
"🌾 Water crops early morning",
"🌱 Use organic fertilizers",
"☀️ Monitor weather before irrigation",
"🚜 Rotate crops to improve soil",
"🌿 Use drip irrigation for water saving"
];

function FarmingTips() {
const [tip, setTip] = useState(tips[0]);

function newTip(){
const random = Math.floor(Math.random()*tips.length);
setTip(tips[random]);
}

return(
<div>
<h3>🌾 Smart Farming Tips</h3>
<p>{tip}</p>
<button onClick={newTip}>New Tip</button>
</div>
);
}

export default FarmingTips;