import React, { useState } from "react";

function AIAssistant() {

  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");

  function askAI() {

    const q = question.toLowerCase();

    if(q.includes("rice")){
      setAnswer("🌾 Rice grows best in warm and humid climates.");
    }
    else if(q.includes("fertilizer")){
      setAnswer("🌱 Use organic fertilizers like compost or vermicompost.");
    }
    else if(q.includes("water")){
      setAnswer("💧 Irrigate crops early morning or evening.");
    }
    else if(q.includes("pest")){
      setAnswer("🐛 Use neem oil spray to control pests naturally.");
    }
    else{
      setAnswer("🤖 I am learning. Please ask about crops, pests, water or fertilizers.");
    }

  }

  return (
    <div>
      <h3>🤖 AI Farming Assistant</h3>

      <input
        type="text"
        placeholder="Ask farming question..."
        value={question}
        onChange={(e)=>setQuestion(e.target.value)}
      />

      <button onClick={askAI}>Ask</button>

      <p>{answer}</p>

    </div>
  );
}

export default AIAssistant;